from fastapi import APIRouter, Depends, HTTPException, Query, Request, status

from ..auth import get_current_user
from ..middleware import limiter
from ..models import (
    LoginRequest,
    UserProfile,
    UserRegisterRequest,
    UserRegisterResponse,
    UserSearchResult,
    UserUpdateRequest,
)
from ..services import user_service

router = APIRouter(prefix="/api/v1/users", tags=["users"])


@router.post("/register", response_model=UserRegisterResponse, status_code=201)
@limiter.limit("5/minute")
async def register(request: Request, req: UserRegisterRequest):
    try:
        user, api_key = await user_service.register_user(
            name=req.name,
            display_name=req.display_name,
            description=req.description,
            password=req.password,
        )
    except ValueError as e:
        raise HTTPException(status_code=status.HTTP_409_CONFLICT, detail=str(e))
    return UserRegisterResponse(
        id=user["id"],
        name=user["name"],
        display_name=user["display_name"],
        api_key=api_key,
    )


@router.post("/login", response_model=UserRegisterResponse)
@limiter.limit("10/minute")
async def login(request: Request, req: LoginRequest):
    try:
        user, api_key = await user_service.authenticate_by_password(
            name=req.name, password=req.password
        )
    except ValueError as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED, detail=str(e)
        )
    return UserRegisterResponse(
        id=user["id"],
        name=user["name"],
        display_name=user["display_name"],
        api_key=api_key,
    )


@router.get("/me", response_model=UserProfile)
async def get_me(current_user: dict = Depends(get_current_user)):
    return UserProfile(**current_user)


@router.patch("/me", response_model=UserProfile)
async def update_me(
    req: UserUpdateRequest, current_user: dict = Depends(get_current_user)
):
    updated = await user_service.update_user(
        user_id=current_user["id"],
        display_name=req.display_name,
        description=req.description,
        password=req.password,
    )
    return UserProfile(**updated)


@router.get("/search", response_model=list[UserSearchResult])
async def search_users(
    q: str = Query(..., min_length=1, max_length=64),
    current_user: dict = Depends(get_current_user),
):
    """Search for users by name or display name."""
    from ..database import get_pool
    pool = get_pool()
    rows = await pool.fetch(
        "SELECT id, name, display_name FROM users "
        "WHERE (name ILIKE $1 OR display_name ILIKE $1) AND id != $2 "
        "LIMIT 20",
        f"%{q}%",
        current_user["id"],
    )
    return [UserSearchResult(**dict(r)) for r in rows]

"""Synchronous httpx client wrapping the Octopus REST API."""

from __future__ import annotations

import httpx


class OctopusError(Exception):
    def __init__(self, status_code: int, detail: str):
        self.status_code = status_code
        self.detail = detail
        super().__init__(f"[{status_code}] {detail}")


class OctopusClient:
    def __init__(self, base_url: str, api_key: str = ""):
        self._base_url = base_url.rstrip("/")
        self._api_key = api_key
        self._http = httpx.Client(base_url=self._base_url, timeout=30)

    def close(self) -> None:
        self._http.close()

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()

    def _headers(self) -> dict[str, str]:
        if not self._api_key:
            return {}
        return {"Authorization": f"Bearer {self._api_key}"}

    def _request(self, method: str, path: str, **kwargs) -> httpx.Response:
        headers = kwargs.pop("headers", {})
        headers.update(self._headers())
        resp = self._http.request(method, path, headers=headers, **kwargs)
        if not resp.is_success:
            detail = ""
            try:
                detail = resp.json().get("detail", resp.text)
            except Exception:
                detail = resp.text
            raise OctopusError(resp.status_code, detail)
        return resp

    def _get(self, path: str, **params) -> dict | list:
        return self._request("GET", path, params=params).json()

