52	  const headers: Record<string, string> = {
53	    "Content-Type": "application/json",
54	    ...(options.headers as Record<string, string>),
55	  };
56	  if (token) {
57	    headers["Authorization"] = `Bearer ${token}`;
58	  }
59	
60	  const res = await fetch(`${API_BASE}${path}`, { ...options, headers });
61	  if (!res.ok) {
62	    const body = await res.json().catch(() => ({ detail: res.statusText }));
63	    throw new Error(body.detail || `API error ${res.status}`);
