def clear_config(scope: Scope = "user") -> None:
    """Remove stored config for the given scope."""
    if scope == "user":
        if USER_CONFIG_FILE.exists():
            USER_CONFIG_FILE.unlink()
        return
    project_path = find_project_config()
    if project_path and project_path.exists():
